import { ComponentModule } from '@/main';
import { authenticate, isAuthenticated } from '@/services/auth.service';

export default {
    name: () => 'login',
    template: () => import('./login.html?raw'),
    data: () => ({
        loading: true,
        submitting: false,
        async init() {
            console.log('login@init');

            // There is a middleware that will redirect if the user is authenticated
            const isLoggedIn = await isAuthenticated();

            this.loading = isLoggedIn;
        },
        async submit(e: SubmitEvent) {
            try {
                console.log('login@submit');
                this.submitting = true;

                /** @ts-expect-error 2339 */
                await authenticate(e.target?.username?.value, e.target?.password?.value);

                /**
                 * sessionStorage handles values instantly in memory but there is a delay until they are persisted.
                 * Therefore, we use "fake" redirection using pinecone router to avoid a page reload, which causes
                 * a race condition where the sessionStorage is not available after a page reload.
                 */
                this.$router.navigate('/');
            } catch (error: any) {
                console.error(error);
                this.submitting = false;
            }
        },
    }),
} as ComponentModule;
